def sieve(n):
    """Return all prime numbers up to n using the Sieve of Eratosthenes."""
    sieve_list = [True] * (n + 1)
    sieve_list[0] = sieve_list[1] = False
    for current_prime in range(2, int(n**0.5) + 1):
        if sieve_list[current_prime]:
            for multiple in range(current_prime**2, n + 1, current_prime):
                sieve_list[multiple] = False
    return [num for num, is_prime in enumerate(sieve_list) if is_prime]
